module timer_core #(
    parameter integer DATA_WIDTH = 32
) (
    input  logic                  pclk,
    input  logic                  presetn,
    input  logic [DATA_WIDTH-1:0] load_q,
    input  logic                  enable_q,
    output logic [DATA_WIDTH-1:0] count_q,
    output logic                  irq
);
    localparam [1:0] DISABLED      = 2'd0,
                     ENABLED_COUNT = 2'd1,
                     RELOAD_IRQ    = 2'd2;

    logic [1:0] state_q;
    logic [1:0] state_d;
    logic [DATA_WIDTH-1:0] count_d;
    logic irq_d;

    wire count_is_zero;
    wire count_is_nonzero;
    wire timer_zero_event;
    wire enabled_decrement_event;
    wire disabled_hold_event;

    assign count_is_zero = (count_q == {DATA_WIDTH{1'b0}});
    assign count_is_nonzero = (count_q != {DATA_WIDTH{1'b0}});
    assign timer_zero_event = enable_q & count_is_zero;
    assign enabled_decrement_event = enable_q & count_is_nonzero;
    assign disabled_hold_event = ~enable_q;

    always @(*) begin
        state_d = state_q;
        count_d = count_q;
        irq_d = 1'b0;

        case (state_q)
            DISABLED: begin
                irq_d = 1'b0;
                count_d = count_q;
                if (enable_q) begin
                    if (count_is_zero) begin
                        state_d = RELOAD_IRQ;
                        count_d = load_q;
                        irq_d = 1'b1;
                    end else begin
                        state_d = ENABLED_COUNT;
                        count_d = count_q - {{(DATA_WIDTH-1){1'b0}}, 1'b1};
                    end
                end else begin
                    state_d = DISABLED;
                end
            end

            ENABLED_COUNT: begin
                irq_d = 1'b0;
                if (!enable_q) begin
                    state_d = DISABLED;
                    count_d = count_q;
                end else if (count_is_zero) begin
                    state_d = RELOAD_IRQ;
                    count_d = load_q;
                    irq_d = 1'b1;
                end else begin
                    state_d = ENABLED_COUNT;
                    count_d = count_q - {{(DATA_WIDTH-1){1'b0}}, 1'b1};
                end
            end

            RELOAD_IRQ: begin
                irq_d = 1'b0;
                if (!enable_q) begin
                    state_d = DISABLED;
                    count_d = count_q;
                end else if (count_is_zero) begin
                    state_d = RELOAD_IRQ;
                    count_d = load_q;
                    irq_d = 1'b1;
                end else begin
                    state_d = ENABLED_COUNT;
                    count_d = count_q - {{(DATA_WIDTH-1){1'b0}}, 1'b1};
                end
            end

            default: begin
                state_d = DISABLED;
                count_d = {DATA_WIDTH{1'b0}};
                irq_d = 1'b0;
            end
        endcase

        if (disabled_hold_event) begin
            state_d = DISABLED;
            count_d = count_q;
            irq_d = 1'b0;
        end else if (timer_zero_event) begin
            state_d = RELOAD_IRQ;
            count_d = load_q;
            irq_d = 1'b1;
        end else if (enabled_decrement_event) begin
            state_d = ENABLED_COUNT;
            count_d = count_q - {{(DATA_WIDTH-1){1'b0}}, 1'b1};
            irq_d = 1'b0;
        end
    end

    always @(posedge pclk or negedge presetn) begin
        if (!presetn) begin
            state_q <= DISABLED;
            count_q <= {DATA_WIDTH{1'b0}};
            irq <= 1'b0;
        end else begin
            state_q <= state_d;
            count_q <= count_d;
            irq <= irq_d;
        end
    end
endmodule

